-- Data migration for the canonical-Card + CardPrinting refactor.
-- Rules-equivalence dedup: only true reprints/alt-arts (identical rules)
-- merge; genuinely-different same-named cards stay separate.
-- GENERATED by gen_migration.py from a prod dump. Run AFTER 01_schema.sql,
-- on a DB snapshot first. Transaction-wrapped; safe to re-run on the same DB.

START TRANSACTION;

-- 1) One printing per existing card (idempotent via NOT EXISTS).
  SELECT c.id, c.pack_id, c.position, c.quantity, c.code, c.illustrator, c.octgnid, c.date_creation, c.date_update
  FROM card c
  WHERE NOT EXISTS (SELECT 1 FROM card_printing cp WHERE cp.card_id = c.id AND cp.pack_id = c.pack_id);

-- 2) Merge map: losing card id -> canonical (earliest) card id.
CREATE TEMPORARY TABLE _merge_map (loser_id INT PRIMARY KEY, canonical_id INT NOT NULL);

-- 3) Repoint the losers' printings onto the canonical card. (Merged cards share
--    the same rules, so printings carry only art differences -- no rules overrides.)
UPDATE card_printing cp JOIN _merge_map m ON cp.card_id = m.loser_id SET cp.card_id = m.canonical_id;

-- 4) Repoint every saved reference (FKs to card.id).
UPDATE deckslot s JOIN _merge_map m ON s.card_id = m.loser_id SET s.card_id = m.canonical_id;
UPDATE decklistslot s JOIN _merge_map m ON s.card_id = m.loser_id SET s.card_id = m.canonical_id;
UPDATE decksideslot s JOIN _merge_map m ON s.card_id = m.loser_id SET s.card_id = m.canonical_id;
UPDATE decklistsideslot s JOIN _merge_map m ON s.card_id = m.loser_id SET s.card_id = m.canonical_id;
UPDATE review s JOIN _merge_map m ON s.card_id = m.loser_id SET s.card_id = m.canonical_id;

-- NOTE: deck-edit history (deckchange.variation) stores card CODES in JSON and is
--   intentionally NOT rewritten -- loser codes become unresolved in the history
--   view only (deck CONTENTS via *_slot are repointed above and stay correct).

-- 5) Collapse duplicate printings now sharing the same canonical card AND pack
--    (e.g. a card printed twice in one pack): keep one, sum quantity.
UPDATE card_printing cp JOIN (
    SELECT MIN(id) keep_id, SUM(quantity) tq FROM card_printing
    GROUP BY card_id, pack_id HAVING COUNT(*) > 1
  ) d ON cp.id = d.keep_id SET cp.quantity = d.tq;
DELETE cp FROM card_printing cp JOIN (
    SELECT card_id, pack_id, MIN(id) keep_id FROM card_printing
    GROUP BY card_id, pack_id HAVING COUNT(*) > 1
  ) d ON cp.card_id = d.card_id AND cp.pack_id = d.pack_id AND cp.id <> d.keep_id;

-- 6) Dedup any slot that now has two rows for the same canonical card (sum qty).
UPDATE deckslot s JOIN (
