    WHERE card_id IN (1,11,14,17,20,23,24,25,26,27,29,30,34,35,39,42,48,50,53,57,59,60,61,66,73,79,89,94,99,100,101,104,109,112,121,125,126,127,130,131,132,134,135,142,149,154,162,163,165,177,178,179,183,184,185,187,188,190,196,197,198,199,200,203,204,213,214,219,230,243,245,256,258,266,267,268,269,270,272,274,275,280,281,282,285,290,291,292,300,301,303,305,308,312,313,320,322,324,327,328,329,330,333,334,338,340,341,342,344,345,349,353,364,422,452,453,454,455,456,458,460,462,463,464,477,489,510,514,516,525,526,540,549,552,579,587,593,597,610,624,625,636,639,641,643,675,678,682,685,689,711,724,730,907,938,950,951,952,961,962,963,966,969,970,980,1067,1069,1076,1094) GROUP BY deck_id, card_id HAVING COUNT(*) > 1
