  ) d ON s.id = d.keep_id SET s.quantity = d.tq;
DELETE s FROM decklistslot s JOIN (
    SELECT decklist_id AS cont, card_id, MIN(id) keep_id FROM decklistslot
    WHERE card_id IN (1,11,14,17,20,23,24,25,26,27,29,30,34,35,39,42,48,50,53,57,59,60,61,66,73,79,89,94,99,100,101,104,109,112,121,125,126,127,130,131,132,134,135,142,149,154,162,163,165,177,178,179,183,184,185,187,188,190,196,197,198,199,200,203,204,213,214,219,230,243,245,256,258,266,267,268,269,270,272,274,275,280,281,282,285,290,291,292,300,301,303,305,308,312,313,320,322,324,327,328,329,330,333,334,338,340,341,342,344,345,349,353,364,422,452,453,454,455,456,458,460,462,463,464,477,489,510,514,516,525,526,540,549,552,579,587,593,597,610,624,625,636,639,641,643,675,678,682,685,689,711,724,730,907,938,950,951,952,961,962,963,966,969,970,980,1067,1069,1076,1094) GROUP BY decklist_id, card_id HAVING COUNT(*) > 1
  ) d ON s.decklist_id = d.cont AND s.card_id = d.card_id AND s.id <> d.keep_id;
UPDATE decksideslot s JOIN (
    SELECT MIN(id) keep_id, SUM(quantity) tq FROM decksideslot
    WHERE card_id IN (1,11,14,17,20,23,24,25,26,27,29,30,34,35,39,42,48,50,53,57,59,60,61,66,73,79,89,94,99,100,101,104,109,112,121,125,126,127,130,131,132,134,135,142,149,154,162,163,165,177,178,179,183,184,185,187,188,190,196,197,198,199,200,203,204,213,214,219,230,243,245,256,258,266,267,268,269,270,272,274,275,280,281,282,285,290,291,292,300,301,303,305,308,312,313,320,322,324,327,328,329,330,333,334,338,340,341,342,344,345,349,353,364,422,452,453,454,455,456,458,460,462,463,464,477,489,510,514,516,525,526,540,549,552,579,587,593,597,610,624,625,636,639,641,643,675,678,682,685,689,711,724,730,907,938,950,951,952,961,962,963,966,969,970,980,1067,1069,1076,1094) GROUP BY deck_id, card_id HAVING COUNT(*) > 1
  ) d ON s.id = d.keep_id SET s.quantity = d.tq;
DELETE s FROM decksideslot s JOIN (
    SELECT deck_id AS cont, card_id, MIN(id) keep_id FROM decksideslot
    WHERE card_id IN (1,11,14,17,20,23,24,25,26,27,29,30,34,35,39,42,48,50,53,57,59,60,61,66,73,79,89,94,99,100,101,104,109,112,121,125,126,127,130,131,132,134,135,142,149,154,162,163,165,177,178,179,183,184,185,187,188,190,196,197,198,199,200,203,204,213,214,219,230,243,245,256,258,266,267,268,269,270,272,274,275,280,281,282,285,290,291,292,300,301,303,305,308,312,313,320,322,324,327,328,329,330,333,334,338,340,341,342,344,345,349,353,364,422,452,453,454,455,456,458,460,462,463,464,477,489,510,514,516,525,526,540,549,552,579,587,593,597,610,624,625,636,639,641,643,675,678,682,685,689,711,724,730,907,938,950,951,952,961,962,963,966,969,970,980,1067,1069,1076,1094) GROUP BY deck_id, card_id HAVING COUNT(*) > 1
  ) d ON s.deck_id = d.cont AND s.card_id = d.card_id AND s.id <> d.keep_id;
UPDATE decklistsideslot s JOIN (
    SELECT MIN(id) keep_id, SUM(quantity) tq FROM decklistsideslot
    WHERE card_id IN (1,11,14,17,20,23,24,25,26,27,29,30,34,35,39,42,48,50,53,57,59,60,61,66,73,79,89,94,99,100,101,104,109,112,121,125,126,127,130,131,132,134,135,142,149,154,162,163,165,177,178,179,183,184,185,187,188,190,196,197,198,199,200,203,204,213,214,219,230,243,245,256,258,266,267,268,269,270,272,274,275,280,281,282,285,290,291,292,300,301,303,305,308,312,313,320,322,324,327,328,329,330,333,334,338,340,341,342,344,345,349,353,364,422,452,453,454,455,456,458,460,462,463,464,477,489,510,514,516,525,526,540,549,552,579,587,593,597,610,624,625,636,639,641,643,675,678,682,685,689,711,724,730,907,938,950,951,952,961,962,963,966,969,970,980,1067,1069,1076,1094) GROUP BY decklist_id, card_id HAVING COUNT(*) > 1
  ) d ON s.id = d.keep_id SET s.quantity = d.tq;
DELETE s FROM decklistsideslot s JOIN (
    SELECT decklist_id AS cont, card_id, MIN(id) keep_id FROM decklistsideslot
    WHERE card_id IN (1,11,14,17,20,23,24,25,26,27,29,30,34,35,39,42,48,50,53,57,59,60,61,66,73,79,89,94,99,100,101,104,109,112,121,125,126,127,130,131,132,134,135,142,149,154,162,163,165,177,178,179,183,184,185,187,188,190,196,197,198,199,200,203,204,213,214,219,230,243,245,256,258,266,267,268,269,270,272,274,275,280,281,282,285,290,291,292,300,301,303,305,308,312,313,320,322,324,327,328,329,330,333,334,338,340,341,342,344,345,349,353,364,422,452,453,454,455,456,458,460,462,463,464,477,489,510,514,516,525,526,540,549,552,579,587,593,597,610,624,625,636,639,641,643,675,678,682,685,689,711,724,730,907,938,950,951,952,961,962,963,966,969,970,980,1067,1069,1076,1094) GROUP BY decklist_id, card_id HAVING COUNT(*) > 1
  ) d ON s.decklist_id = d.cont AND s.card_id = d.card_id AND s.id <> d.keep_id;

-- 7) Delete the now-merged loser card rows.
DELETE c FROM card c JOIN _merge_map m ON c.id = m.loser_id;

-- 8) Flag the repackaged products (collection page groups them separately).
UPDATE pack SET is_repackaged = 1 WHERE id IN (61,85,98,99,100,101);

-- 9) Correct the placeholder release dates on the repackaged packs.
--    The original data had fake 2011 dates; actual release dates are:
--    Two-Player Limited Edition Starter: July 2017
--    Revised Core Campaign-Only + 4 Starter Decks: November 2022
UPDATE pack SET date_release = '2017-07-06' WHERE id = 61;
UPDATE pack SET date_release = '2022-11-04' WHERE id = 85;
UPDATE pack SET date_release = '2022-11-04' WHERE id = 98;
UPDATE pack SET date_release = '2022-11-04' WHERE id = 99;
UPDATE pack SET date_release = '2022-11-04' WHERE id = 100;
UPDATE pack SET date_release = '2022-11-04' WHERE id = 101;

DROP TEMPORARY TABLE _merge_map;
COMMIT;
